package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Field;
import java.util.Objects;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class GsonBuilderTest {

  private GsonBuilder gsonBuilder;

  @BeforeEach
  void setUp() {
    gsonBuilder = new GsonBuilder();
  }

  @Test
  void setNumberToNumberStrategy_withValidStrategy_shouldSetAndReturnThis() throws Exception {
    ToNumberStrategy mockStrategy = mock(ToNumberStrategy.class);

    GsonBuilder returned = gsonBuilder.setNumberToNumberStrategy(mockStrategy);

    assertSame(gsonBuilder, returned);

    Field field = GsonBuilder.class.getDeclaredField("numberToNumberStrategy");
    field.setAccessible(true);
    Object fieldValue = field.get(gsonBuilder);

    assertSame(mockStrategy, fieldValue);
  }

  @Test
  void setNumberToNumberStrategy_withNull_shouldThrowNullPointerException() {
    NullPointerException thrown = assertThrows(NullPointerException.class, () -> {
      gsonBuilder.setNumberToNumberStrategy(null);
    });
    assertEquals("numberToNumberStrategy is marked non-null but is null", thrown.getMessage(), 
      // message can vary, so just check not null
      () -> thrown.getMessage() == null ? "message is null" : null);
  }
}
